dashboard.definition:
{
  "title": "Source - Linux",
  "description": "Linux OS metrics — prevent server outages by monitoring CPU, memory, and disk before they become incidents",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Linux Events Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:cpu\" OR sourcetype=\"FAKE:vmstat\" OR sourcetype=\"FAKE:df\" OR sourcetype=\"FAKE:iostat\" OR sourcetype=\"FAKE:interfaces\") by _time span=1h"
      }
    },
    "ds_hosts_reporting": {
      "type": "ds.search",
      "name": "Hosts Monitored",
      "options": {
        "query": "| tstats dc(host) as count where index=fake_tshrt (sourcetype=\"FAKE:cpu\" OR sourcetype=\"FAKE:vmstat\" OR sourcetype=\"FAKE:df\" OR sourcetype=\"FAKE:iostat\" OR sourcetype=\"FAKE:interfaces\")"
      }
    },
    "ds_avg_cpu": {
      "type": "ds.search",
      "name": "Avg CPU %",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cpu\" pctUser=* | stats avg(pctUser) as count | eval count=round(count,1).\"%\""
      }
    },
    "ds_disk_critical": {
      "type": "ds.search",
      "name": "Hosts with Disk >90%",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:df\" UsedPct=* | stats latest(UsedPct) as used by host, mount | where used>90 | stats dc(host) as count"
      }
    },
    "ds_cpu_over_time": {
      "type": "ds.search",
      "name": "CPU Usage Over Time by Host",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:cpu\" pctUser=* | timechart span=1h avg(pctUser) by host"
      }
    },
    "ds_memory_over_time": {
      "type": "ds.search",
      "name": "Memory Usage Over Time by Host",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:vmstat\" memUsedPct=* | timechart span=1h avg(memUsedPct) by host"
      }
    },
    "ds_events_by_sourcetype": {
      "type": "ds.search",
      "name": "Events by Sourcetype",
      "options": {
        "query": "| tstats count where index=fake_tshrt (sourcetype=\"FAKE:cpu\" OR sourcetype=\"FAKE:vmstat\" OR sourcetype=\"FAKE:df\" OR sourcetype=\"FAKE:iostat\" OR sourcetype=\"FAKE:interfaces\") by sourcetype | sort -count"
      }
    },
    "ds_disk_usage": {
      "type": "ds.search",
      "name": "Current Disk Space",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:df\" UsedPct=* | stats latest(UsedPct) as UsedPct latest(Size) as Size latest(Used) as Used latest(Avail) as Avail by host, mount | sort -UsedPct | head 20 | rename host as \"Host\" mount as \"Mount\" UsedPct as \"Use %\" Size as \"Total\" Used as \"Used\" Avail as \"Available\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Linux\n\n**Sourcetypes:** `FAKE:cpu`, `FAKE:vmstat`, `FAKE:df`, `FAKE:iostat`, `FAKE:interfaces` | **Coverage:** All Linux servers (WEB-01/02, SAP, Bastion, MON-ATL-01) | **Format:** Key-value pairs\n\n**Why monitor?** Prevent server outages by catching CPU spikes, memory exhaustion, and disk space depletion before they cascade into application failures and lost revenue.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_events": {
      "type": "splunk.singlevalue",
      "title": "Total Metrics",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_hosts": {
      "type": "splunk.singlevalue",
      "title": "Hosts Monitored",
      "dataSources": { "primary": "ds_hosts_reporting" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_avg_cpu": {
      "type": "splunk.singlevalue",
      "title": "Avg CPU %",
      "dataSources": { "primary": "ds_avg_cpu" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#F8BE34",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_disk_critical": {
      "type": "splunk.singlevalue",
      "title": "Hosts with Disk >90%",
      "dataSources": { "primary": "ds_disk_critical" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_cpu_over_time": {
      "type": "splunk.line",
      "title": "CPU Usage Over Time by Host",
      "dataSources": { "primary": "ds_cpu_over_time" },
      "options": {
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "% User CPU",
        "yAxisTitleVisibility": "show",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_memory_over_time": {
      "type": "splunk.line",
      "title": "Memory Usage Over Time by Host",
      "dataSources": { "primary": "ds_memory_over_time" },
      "options": {
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "% Memory Used",
        "yAxisTitleVisibility": "show",
        "seriesColors": ["#00D2FF", "#7B56DB", "#53A051", "#F8BE34", "#DC4E41", "#009CEB", "#F1813F", "#00CDAF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_events_by_sourcetype": {
      "type": "splunk.pie",
      "title": "Events by Sourcetype",
      "dataSources": { "primary": "ds_events_by_sourcetype" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColors": ["#53A051", "#00D2FF", "#DC4E41", "#F8BE34", "#7B56DB"]
      }
    },
    "viz_disk_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Current Disk Space",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_disk_usage": {
      "type": "splunk.table",
      "title": "Current Disk Space",
      "dataSources": { "primary": "ds_disk_usage" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 150 } },
      { "item": "viz_kpi_total_events", "type": "block", "position": { "x": 0, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_hosts", "type": "block", "position": { "x": 300, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_avg_cpu", "type": "block", "position": { "x": 600, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_kpi_disk_critical", "type": "block", "position": { "x": 900, "y": 150, "w": 300, "h": 120 } },
      { "item": "viz_cpu_over_time", "type": "block", "position": { "x": 0, "y": 270, "w": 600, "h": 350 } },
      { "item": "viz_memory_over_time", "type": "block", "position": { "x": 600, "y": 270, "w": 600, "h": 350 } },
      { "item": "viz_events_by_sourcetype", "type": "block", "position": { "x": 0, "y": 620, "w": 1200, "h": 300 } },
      { "item": "viz_disk_header", "type": "block", "position": { "x": 0, "y": 920, "w": 1200, "h": 50 } },
      { "item": "viz_disk_usage", "type": "block", "position": { "x": 0, "y": 970, "w": 1200, "h": 400 } }
    ]
  }
}
